import{_ as s,c as a,e as p,o as e}from"./app-B2AWmW0e.js";const t={};function l(c,n){return e(),a("div",null,[...n[0]||(n[0]=[p(`<h1 id="go-接口与代码复用-替代继承的设计哲学" tabindex="-1"><a class="header-anchor" href="#go-接口与代码复用-替代继承的设计哲学"><span>Go 接口与代码复用：替代继承的设计哲学</span></a></h1><h2 id="一、前言" tabindex="-1"><a class="header-anchor" href="#一、前言"><span>一、前言</span></a></h2><p>Go 是 Google 设计的类 C 静态类型语言，兼顾底层性能与开发效率。它并非传统意义上的面向对象（OOP）语言 —— 没有 class 关键字，也不支持传统的 “继承” 语法，但通过 <strong>接口的隐式实现</strong> 和 <strong>结构体组合（嵌入）</strong>，Go 能灵活实现 OOP 的核心特性（多态、代码复用），且设计更简洁、无继承带来的耦合问题。 与 C++ 相比，Go 的设计哲学是 “<strong>组合优于继承</strong>”：用接口实现多态，用结构体嵌入实现代码复用，既避免了继承的复杂语法，又解决了多重继承的歧义问题。本文将通过类比 C++ 的接口 / 继承逻辑，详解 Go 如何实现类似效果。</p><h2 id="二、go-中的-单一复用-类似单一继承" tabindex="-1"><a class="header-anchor" href="#二、go-中的-单一复用-类似单一继承"><span>二、Go 中的 “单一复用”（类似单一继承）</span></a></h2><p>C++ 的单一继承核心是 “一个子类继承一个父类 / 接口”，Go 中通过两种方式实现类似效果：<strong>仅用接口实现多态</strong>（无代码复用，仅约束行为）、<strong>结构体组合（嵌入）+ 接口</strong>（既有代码复用，又有多态）。</p><h3 id="_2-1-仅通过接口实现-隐式多态" tabindex="-1"><a class="header-anchor" href="#_2-1-仅通过接口实现-隐式多态"><span>2.1 仅通过接口实现（隐式多态）</span></a></h3><p>C++ 的接口是 “纯虚函数集合”，子类需显式声明继承并实现所有接口方法；而 Go 的接口是 “方法签名集合”，<strong>无需显式声明实现</strong>—— 只要结构体实现了接口的所有方法，就自动满足该接口，这就是 “隐式实现”，也是 Go 接口的核心特性。</p><h4 id="类比-c-伪代码" tabindex="-1"><a class="header-anchor" href="#类比-c-伪代码"><span>类比 C++ 伪代码</span></a></h4><div class="language-cpp line-numbers-mode" data-highlighter="prismjs" data-ext="cpp"><pre><code><span class="line"><span class="token comment">// C++ 需显式声明继承接口</span></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">IFruit</span> <span class="token punctuation">{</span></span>
<span class="line"><span class="token keyword">public</span><span class="token operator">:</span></span>
<span class="line">    <span class="token keyword">virtual</span> std<span class="token double-colon punctuation">::</span>string <span class="token function">GetName</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">const</span> <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">virtual</span> <span class="token keyword">void</span> <span class="token function">SetName</span><span class="token punctuation">(</span>std<span class="token double-colon punctuation">::</span>string name<span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">virtual</span> std<span class="token double-colon punctuation">::</span>string <span class="token function">GetType</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">const</span> <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">Apple</span> <span class="token operator">:</span> <span class="token base-clause"><span class="token keyword">public</span> <span class="token class-name">IFruit</span></span> <span class="token punctuation">{</span> <span class="token comment">// 显式继承</span></span>
<span class="line"><span class="token keyword">public</span><span class="token operator">:</span></span>
<span class="line">    std<span class="token double-colon punctuation">::</span>string <span class="token function">GetName</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">const</span> <span class="token keyword">override</span> <span class="token punctuation">{</span> <span class="token comment">/* 实现 */</span> <span class="token punctuation">}</span></span>
<span class="line">    <span class="token keyword">void</span> <span class="token function">SetName</span><span class="token punctuation">(</span>std<span class="token double-colon punctuation">::</span>string name<span class="token punctuation">)</span> <span class="token keyword">override</span> <span class="token punctuation">{</span> <span class="token comment">/* 实现 */</span> <span class="token punctuation">}</span></span>
<span class="line">    std<span class="token double-colon punctuation">::</span>string <span class="token function">GetType</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">const</span> <span class="token keyword">override</span> <span class="token punctuation">{</span> <span class="token keyword">return</span> <span class="token string">&quot;apple&quot;</span><span class="token punctuation">;</span> <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="go-实现代码" tabindex="-1"><a class="header-anchor" href="#go-实现代码"><span>Go 实现代码</span></a></h4><p>首先定义接口（仅约束行为，无实现）：</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token comment">// 定义 Fruit 接口：仅声明方法签名，无实现</span></span>
<span class="line"><span class="token keyword">type</span> FruitType <span class="token builtin">string</span> <span class="token comment">// 补充类型定义，使代码可运行</span></span>
<span class="line"><span class="token keyword">const</span> <span class="token punctuation">(</span></span>
<span class="line">    BananaType FruitType <span class="token operator">=</span> <span class="token string">&quot;banana&quot;</span></span>
<span class="line">    AppleType  FruitType <span class="token operator">=</span> <span class="token string">&quot;apple&quot;</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">type</span> Fruit <span class="token keyword">interface</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token function">GetName</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">string</span></span>
<span class="line">    <span class="token function">SetName</span><span class="token punctuation">(</span>name <span class="token builtin">string</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token function">GetType</span><span class="token punctuation">(</span><span class="token punctuation">)</span> FruitType <span class="token comment">// 明确类型，避免歧义</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>定义 Banana 结构体，隐式实现 Fruit 接口：</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token keyword">type</span> Banana <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    name   <span class="token builtin">string</span></span>
<span class="line">    energy <span class="token builtin">float32</span> <span class="token comment">// 自定义字段</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 构造函数：初始化 Banana 实例</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">NewBanana</span><span class="token punctuation">(</span>name <span class="token builtin">string</span><span class="token punctuation">)</span> <span class="token operator">*</span>Banana <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token operator">&amp;</span>Banana<span class="token punctuation">{</span></span>
<span class="line">        name<span class="token punctuation">:</span>   name<span class="token punctuation">,</span></span>
<span class="line">        energy<span class="token punctuation">:</span> <span class="token number">0</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 实现 Fruit 接口的所有方法（隐式满足 Fruit 接口）</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>b <span class="token operator">*</span>Banana<span class="token punctuation">)</span> <span class="token function">GetName</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">string</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> b<span class="token punctuation">.</span>name</span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>b <span class="token operator">*</span>Banana<span class="token punctuation">)</span> <span class="token function">SetName</span><span class="token punctuation">(</span>name <span class="token builtin">string</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    b<span class="token punctuation">.</span>name <span class="token operator">=</span> name</span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>b <span class="token operator">*</span>Banana<span class="token punctuation">)</span> <span class="token function">GetType</span><span class="token punctuation">(</span><span class="token punctuation">)</span> FruitType <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> BananaType</span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Banana 自定义方法（接口未约束，仅自身可用）</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>b <span class="token operator">*</span>Banana<span class="token punctuation">)</span> <span class="token function">SetEnergy</span><span class="token punctuation">(</span>energy <span class="token builtin">float32</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    b<span class="token punctuation">.</span>energy <span class="token operator">=</span> energy</span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>b <span class="token operator">*</span>Banana<span class="token punctuation">)</span> <span class="token function">GetEnergy</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">float32</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> b<span class="token punctuation">.</span>energy</span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="接口的两种使用方式-体现多态" tabindex="-1"><a class="header-anchor" href="#接口的两种使用方式-体现多态"><span>接口的两种使用方式（体现多态）</span></a></h4><h5 id="_1-赋值给接口变量-通过接口统一调用-屏蔽具体实现" tabindex="-1"><a class="header-anchor" href="#_1-赋值给接口变量-通过接口统一调用-屏蔽具体实现"><span>1. 赋值给接口变量：通过接口统一调用，屏蔽具体实现</span></a></h5><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token keyword">var</span> fruit Fruit <span class="token comment">// 接口变量</span></span>
<span class="line">fruit <span class="token operator">=</span> <span class="token function">NewBanana</span><span class="token punctuation">(</span><span class="token string">&quot;big banana&quot;</span><span class="token punctuation">)</span> <span class="token comment">// 隐式转换，无需显式声明</span></span>
<span class="line">fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span>fruit<span class="token punctuation">.</span><span class="token function">GetName</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// 输出：big banana（调用 Banana 的实现）</span></span>
<span class="line">fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span>fruit<span class="token punctuation">.</span><span class="token function">GetType</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// 输出：banana</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_2-直接使用结构体实例-可调用接口方法-自定义方法" tabindex="-1"><a class="header-anchor" href="#_2-直接使用结构体实例-可调用接口方法-自定义方法"><span>2. 直接使用结构体实例：可调用接口方法 + 自定义方法</span></a></h5><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line">banana <span class="token operator">:=</span> <span class="token function">NewBanana</span><span class="token punctuation">(</span><span class="token string">&quot;little banana&quot;</span><span class="token punctuation">)</span></span>
<span class="line">banana<span class="token punctuation">.</span><span class="token function">SetEnergy</span><span class="token punctuation">(</span><span class="token number">100</span><span class="token punctuation">)</span> <span class="token comment">// 调用自定义方法</span></span>
<span class="line">fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span>banana<span class="token punctuation">.</span><span class="token function">GetEnergy</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// 输出：100</span></span>
<span class="line">fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span>banana<span class="token punctuation">.</span><span class="token function">GetName</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// 输出：little banana（调用接口方法）</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_3-工厂方法统一创建实例-增强多态灵活性" tabindex="-1"><a class="header-anchor" href="#_3-工厂方法统一创建实例-增强多态灵活性"><span>3. 工厂方法统一创建实例（增强多态灵活性）</span></a></h5><p>补充 NewFruit 实现，根据类型创建不同 Fruit 实例：</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token keyword">func</span> <span class="token function">NewFruit</span><span class="token punctuation">(</span>fruitType FruitType<span class="token punctuation">,</span> name <span class="token builtin">string</span><span class="token punctuation">)</span> Fruit <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">switch</span> fruitType <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">case</span> BananaType<span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">return</span> <span class="token function">NewBanana</span><span class="token punctuation">(</span>name<span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">case</span> AppleType<span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">return</span> <span class="token function">NewApple</span><span class="token punctuation">(</span>name<span class="token punctuation">)</span> <span class="token comment">// 需实现 Apple 结构体（类似 Banana）</span></span>
<span class="line">    <span class="token keyword">default</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">return</span> <span class="token boolean">nil</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 使用工厂方法</span></span>
<span class="line">apple <span class="token operator">:=</span> <span class="token function">NewFruit</span><span class="token punctuation">(</span>AppleType<span class="token punctuation">,</span> <span class="token string">&quot;red apple&quot;</span><span class="token punctuation">)</span></span>
<span class="line">banana <span class="token operator">:=</span> <span class="token function">NewFruit</span><span class="token punctuation">(</span>BananaType<span class="token punctuation">,</span> <span class="token string">&quot;yellow banana&quot;</span><span class="token punctuation">)</span></span>
<span class="line">fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span>apple<span class="token punctuation">.</span><span class="token function">GetName</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> banana<span class="token punctuation">.</span><span class="token function">GetName</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// 统一调用接口方法\`</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-2-结构体组合-嵌入-实现代码复用-类似基类继承" tabindex="-1"><a class="header-anchor" href="#_2-2-结构体组合-嵌入-实现代码复用-类似基类继承"><span>2.2 结构体组合（嵌入）实现代码复用（类似基类继承）</span></a></h3><p>C++ 中通过 “子类继承基类” 复用基类代码，Go 中通过 “结构体嵌入”（将一个结构体作为另一个结构体的匿名字段）实现代码复用 —— 嵌入的结构体（称为 “嵌入类型”）的方法和字段，会被外层结构体 “继承”（实际是隐式代理），外层结构体可直接调用，也可覆盖这些方法。</p><h4 id="类比-c-伪代码-1" tabindex="-1"><a class="header-anchor" href="#类比-c-伪代码-1"><span>类比 C++ 伪代码</span></a></h4><div class="language-cpp line-numbers-mode" data-highlighter="prismjs" data-ext="cpp"><pre><code><span class="line"><span class="token comment">// 基类（含部分实现）</span></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">VehicleBase</span> <span class="token operator">:</span> <span class="token base-clause"><span class="token keyword">public</span> <span class="token class-name">IVehicle</span></span> <span class="token punctuation">{</span></span>
<span class="line"><span class="token keyword">public</span><span class="token operator">:</span></span>
<span class="line">    <span class="token keyword">void</span> <span class="token function">SetWheelCount</span><span class="token punctuation">(</span><span class="token keyword">int</span> count<span class="token punctuation">)</span> <span class="token keyword">override</span> <span class="token punctuation">{</span> wheelCount <span class="token operator">=</span> count<span class="token punctuation">;</span> <span class="token punctuation">}</span></span>
<span class="line">    <span class="token keyword">int</span> <span class="token function">GetWheelCount</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">const</span> <span class="token keyword">override</span> <span class="token punctuation">{</span> <span class="token keyword">return</span> wheelCount<span class="token punctuation">;</span> <span class="token punctuation">}</span></span>
<span class="line">    std<span class="token double-colon punctuation">::</span>string <span class="token function">ToString</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">const</span> <span class="token keyword">override</span> <span class="token punctuation">{</span> <span class="token keyword">return</span> <span class="token string">&quot;vehicle -&gt; &quot;</span><span class="token punctuation">;</span> <span class="token punctuation">}</span></span>
<span class="line"><span class="token keyword">private</span><span class="token operator">:</span></span>
<span class="line">    <span class="token keyword">int</span> wheelCount<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 子类继承基类，复用方法并可覆盖</span></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">Bus</span> <span class="token operator">:</span> <span class="token base-clause"><span class="token keyword">public</span> <span class="token class-name">VehicleBase</span></span> <span class="token punctuation">{</span></span>
<span class="line"><span class="token keyword">public</span><span class="token operator">:</span></span>
<span class="line">    std<span class="token double-colon punctuation">::</span>string <span class="token function">GetName</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">const</span> <span class="token keyword">override</span> <span class="token punctuation">{</span> <span class="token keyword">return</span> name<span class="token punctuation">;</span> <span class="token punctuation">}</span></span>
<span class="line">    <span class="token keyword">void</span> <span class="token function">SetName</span><span class="token punctuation">(</span>std<span class="token double-colon punctuation">::</span>string n<span class="token punctuation">)</span> <span class="token keyword">override</span> <span class="token punctuation">{</span> name <span class="token operator">=</span> n<span class="token punctuation">;</span> <span class="token punctuation">}</span></span>
<span class="line">    std<span class="token double-colon punctuation">::</span>string <span class="token function">ToString</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">const</span> <span class="token keyword">override</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token keyword">return</span> <span class="token class-name">VehicleBase</span><span class="token double-colon punctuation">::</span><span class="token function">ToString</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">+</span> <span class="token string">&quot;Bus -&gt; &quot;</span> <span class="token operator">+</span> name<span class="token punctuation">;</span> <span class="token comment">// 调用基类方法</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token keyword">private</span><span class="token operator">:</span></span>
<span class="line">    std<span class="token double-colon punctuation">::</span>string name<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="go-实现代码-1" tabindex="-1"><a class="header-anchor" href="#go-实现代码-1"><span>Go 实现代码</span></a></h4><h5 id="_1-定义接口-约束核心行为" tabindex="-1"><a class="header-anchor" href="#_1-定义接口-约束核心行为"><span>1. 定义接口（约束核心行为）：</span></a></h5><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token keyword">type</span> VehicleType <span class="token builtin">string</span></span>
<span class="line"><span class="token keyword">const</span> <span class="token punctuation">(</span></span>
<span class="line">    BusType VehicleType <span class="token operator">=</span> <span class="token string">&quot;bus&quot;</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">type</span> Vehicle <span class="token keyword">interface</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token function">GetType</span><span class="token punctuation">(</span><span class="token punctuation">)</span> VehicleType</span>
<span class="line">    <span class="token function">GetName</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">string</span></span>
<span class="line">    <span class="token function">SetName</span><span class="token punctuation">(</span>name <span class="token builtin">string</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token function">SetWheelCount</span><span class="token punctuation">(</span>count <span class="token builtin">int</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token function">GetWheelCount</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">int</span></span>
<span class="line">    <span class="token function">ToString</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">string</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_2-定义-嵌入结构体-类似基类-提供通用实现" tabindex="-1"><a class="header-anchor" href="#_2-定义-嵌入结构体-类似基类-提供通用实现"><span>2. 定义 “嵌入结构体”（类似基类，提供通用实现）：</span></a></h5><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token comment">// vehicleImpl 是通用实现，作为嵌入类型供其他结构体复用</span></span>
<span class="line"><span class="token keyword">type</span> vehicleImpl <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    wheelCount <span class="token builtin">int</span> <span class="token comment">// 通用字段</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 通用方法实现（供嵌入者复用）</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>v <span class="token operator">*</span>vehicleImpl<span class="token punctuation">)</span> <span class="token function">SetWheelCount</span><span class="token punctuation">(</span>count <span class="token builtin">int</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    v<span class="token punctuation">.</span>wheelCount <span class="token operator">=</span> count</span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>v <span class="token operator">*</span>vehicleImpl<span class="token punctuation">)</span> <span class="token function">GetWheelCount</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">int</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> v<span class="token punctuation">.</span>wheelCount</span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>v <span class="token operator">*</span>vehicleImpl<span class="token punctuation">)</span> <span class="token function">ToString</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">string</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token string">&quot;vehicle -&gt; &quot;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_3-定义外层结构体-嵌入-vehicleimpl-复用代码" tabindex="-1"><a class="header-anchor" href="#_3-定义外层结构体-嵌入-vehicleimpl-复用代码"><span>3. 定义外层结构体（嵌入 vehicleImpl，复用代码）：</span></a></h5><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token comment">// Bus 结构体通过嵌入 vehicleImpl，复用其方法和字段</span></span>
<span class="line"><span class="token keyword">type</span> Bus <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    vehicleImpl <span class="token comment">// 匿名嵌入（组合），无需显式调用</span></span>
<span class="line">    name        <span class="token builtin">string</span> <span class="token comment">// 自身字段</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 构造函数：初始化 Bus 实例（需初始化嵌入结构体）</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">NewBus</span><span class="token punctuation">(</span>name <span class="token builtin">string</span><span class="token punctuation">)</span> <span class="token operator">*</span>Bus <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token operator">&amp;</span>Bus<span class="token punctuation">{</span></span>
<span class="line">        name<span class="token punctuation">:</span> name<span class="token punctuation">,</span></span>
<span class="line">        vehicleImpl<span class="token punctuation">:</span> vehicleImpl<span class="token punctuation">{</span> <span class="token comment">// 初始化嵌入结构体</span></span>
<span class="line">            wheelCount<span class="token punctuation">:</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token comment">// 公交车默认4个轮子</span></span>
<span class="line">        <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 实现 Vehicle 接口的剩余方法（未被 vehicleImpl 实现的部分）</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>b <span class="token operator">*</span>Bus<span class="token punctuation">)</span> <span class="token function">GetType</span><span class="token punctuation">(</span><span class="token punctuation">)</span> VehicleType <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> BusType</span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>b <span class="token operator">*</span>Bus<span class="token punctuation">)</span> <span class="token function">GetName</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">string</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> b<span class="token punctuation">.</span>name</span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>b <span class="token operator">*</span>Bus<span class="token punctuation">)</span> <span class="token function">SetName</span><span class="token punctuation">(</span>name <span class="token builtin">string</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    b<span class="token punctuation">.</span>name <span class="token operator">=</span> name</span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 覆盖嵌入结构体的 ToString 方法</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>b <span class="token operator">*</span>Bus<span class="token punctuation">)</span> <span class="token function">ToString</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">string</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// 调用嵌入结构体的被覆盖方法：b.vehicleImpl.ToString()</span></span>
<span class="line">    <span class="token keyword">return</span> b<span class="token punctuation">.</span>vehicleImpl<span class="token punctuation">.</span><span class="token function">ToString</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">+</span> fmt<span class="token punctuation">.</span><span class="token function">Sprintf</span><span class="token punctuation">(</span><span class="token string">&quot;Bus -&gt; %s (wheels: %d)&quot;</span><span class="token punctuation">,</span> b<span class="token punctuation">.</span><span class="token function">GetName</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> b<span class="token punctuation">.</span><span class="token function">GetWheelCount</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="核心特性说明" tabindex="-1"><a class="header-anchor" href="#核心特性说明"><span>核心特性说明</span></a></h5><ul><li>代码复用：<code>Bus</code> 无需重新实现 <code>SetWheelCount</code>、<code>GetWheelCount</code>，直接复用 <code>vehicleImpl</code> 的方法；</li><li>方法覆盖：<code>Bus</code> 定义了与 <code>vehicleImpl</code> 同名的 <code>ToString</code> 方法，会覆盖嵌入结构体的方法，优先调用外层方法；</li><li>显式调用嵌入方法：通过 <code>b.vehicleImpl.ToString()</code> 可调用被覆盖的嵌入结构体方法；</li><li>字段访问：嵌入结构体的字段可直接访问（<code>b.wheelCount</code>），也可显式访问（<code>b.vehicleImpl.wheelCount</code>）。</li></ul><h2 id="三、go-中的-多组合-类似多重继承" tabindex="-1"><a class="header-anchor" href="#三、go-中的-多组合-类似多重继承"><span>三、Go 中的 “多组合”（类似多重继承）</span></a></h2><p>C++ 支持多重继承（一个类继承多个父类），但容易引发 “菱形继承”（多个父类继承自同一基类）的歧义问题。Go 本身<strong>不支持传统多重继承</strong>，但通过 “多嵌入”（一个结构体嵌入多个结构体），可实现类似 “多重继承” 的效果 —— 复用多个嵌入结构体的方法和字段，且无歧义。</p><h3 id="类比-c-伪代码-2" tabindex="-1"><a class="header-anchor" href="#类比-c-伪代码-2"><span>类比 C++ 伪代码</span></a></h3><div class="language-cpp line-numbers-mode" data-highlighter="prismjs" data-ext="cpp"><pre><code><span class="line"><span class="token keyword">class</span> <span class="token class-name">Father</span> <span class="token punctuation">{</span></span>
<span class="line"><span class="token keyword">public</span><span class="token operator">:</span></span>
<span class="line">    std<span class="token double-colon punctuation">::</span>string <span class="token function">GetName</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">const</span> <span class="token punctuation">{</span> <span class="token keyword">return</span> <span class="token string">&quot;Tony&quot;</span><span class="token punctuation">;</span> <span class="token punctuation">}</span></span>
<span class="line">    std<span class="token double-colon punctuation">::</span>string <span class="token function">Say</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">const</span> <span class="token punctuation">{</span> <span class="token keyword">return</span> <span class="token string">&quot;I am &quot;</span> <span class="token operator">+</span> <span class="token function">GetName</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">Mother</span> <span class="token punctuation">{</span></span>
<span class="line"><span class="token keyword">public</span><span class="token operator">:</span></span>
<span class="line">    std<span class="token double-colon punctuation">::</span>string <span class="token function">GetName</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">const</span> <span class="token punctuation">{</span> <span class="token keyword">return</span> <span class="token string">&quot;Aurora&quot;</span><span class="token punctuation">;</span> <span class="token punctuation">}</span></span>
<span class="line">    std<span class="token double-colon punctuation">::</span>string <span class="token function">Say</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">const</span> <span class="token punctuation">{</span> <span class="token keyword">return</span> <span class="token string">&quot;I am &quot;</span> <span class="token operator">+</span> <span class="token function">GetName</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 多重继承：同时继承 Father 和 Mother</span></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">Child</span> <span class="token operator">:</span> <span class="token base-clause"><span class="token keyword">public</span> <span class="token class-name">Father</span><span class="token punctuation">,</span> <span class="token keyword">public</span> <span class="token class-name">Mother</span></span> <span class="token punctuation">{</span></span>
<span class="line"><span class="token keyword">public</span><span class="token operator">:</span></span>
<span class="line">    std<span class="token double-colon punctuation">::</span>string <span class="token function">GetName</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">const</span> <span class="token punctuation">{</span> <span class="token keyword">return</span> <span class="token string">&quot;Jerry&quot;</span><span class="token punctuation">;</span> <span class="token punctuation">}</span></span>
<span class="line">    std<span class="token double-colon punctuation">::</span>string <span class="token function">Say</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">const</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token comment">// 显式调用父类方法，避免歧义</span></span>
<span class="line">        <span class="token keyword">return</span> <span class="token string">&quot;I am &quot;</span> <span class="token operator">+</span> <span class="token function">GetName</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">+</span> <span class="token string">&quot;, Father: &quot;</span> <span class="token operator">+</span> <span class="token class-name">Father</span><span class="token double-colon punctuation">::</span><span class="token function">Say</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">+</span> <span class="token string">&quot;, Mother: &quot;</span> <span class="token operator">+</span> <span class="token class-name">Mother</span><span class="token double-colon punctuation">::</span><span class="token function">Say</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="go-实现代码-多嵌入结构体" tabindex="-1"><a class="header-anchor" href="#go-实现代码-多嵌入结构体"><span>Go 实现代码（多嵌入结构体）</span></a></h3><h4 id="_1-定义两个-被组合-的结构体-类似父类" tabindex="-1"><a class="header-anchor" href="#_1-定义两个-被组合-的结构体-类似父类"><span>1. 定义两个 “被组合” 的结构体（类似父类）：</span></a></h4><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token comment">// Father 结构体（提供一组方法）</span></span>
<span class="line"><span class="token keyword">type</span> Father <span class="token keyword">struct</span><span class="token punctuation">{</span><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">NewFather</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">*</span>Father <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token operator">&amp;</span>Father<span class="token punctuation">{</span><span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>f <span class="token operator">*</span>Father<span class="token punctuation">)</span> <span class="token function">GetName</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">string</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token string">&quot;Tony&quot;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>f <span class="token operator">*</span>Father<span class="token punctuation">)</span> <span class="token function">Say</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">string</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token string">&quot;I am &quot;</span> <span class="token operator">+</span> f<span class="token punctuation">.</span><span class="token function">GetName</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Mother 结构体（提供另一组方法）</span></span>
<span class="line"><span class="token keyword">type</span> Mother <span class="token keyword">struct</span><span class="token punctuation">{</span><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">NewMother</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">*</span>Mother <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token operator">&amp;</span>Mother<span class="token punctuation">{</span><span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>m <span class="token operator">*</span>Mother<span class="token punctuation">)</span> <span class="token function">GetName</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">string</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token string">&quot;Aurora&quot;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>m <span class="token operator">*</span>Mother<span class="token punctuation">)</span> <span class="token function">Say</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">string</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token string">&quot;I am &quot;</span> <span class="token operator">+</span> m<span class="token punctuation">.</span><span class="token function">GetName</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-定义-child-结构体-嵌入-father-和-mother" tabindex="-1"><a class="header-anchor" href="#_2-定义-child-结构体-嵌入-father-和-mother"><span>2. 定义 Child 结构体（嵌入 Father 和 Mother）：</span></a></h4><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token comment">// Child 嵌入两个结构体，复用其方法</span></span>
<span class="line"><span class="token keyword">type</span> Child <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token operator">*</span>Mother <span class="token comment">// 指针嵌入（需初始化指针）</span></span>
<span class="line">    <span class="token operator">*</span>Father <span class="token comment">// 指针嵌入</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 构造函数：初始化 Child 及嵌入的结构体指针</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">NewChild</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">*</span>Child <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token operator">&amp;</span>Child<span class="token punctuation">{</span></span>
<span class="line">        Mother<span class="token punctuation">:</span> <span class="token function">NewMother</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token comment">// 初始化 Mother 指针</span></span>
<span class="line">        Father<span class="token punctuation">:</span> <span class="token function">NewFather</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token comment">// 初始化 Father 指针</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 覆盖嵌入结构体的同名方法（避免调用歧义）</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>c <span class="token operator">*</span>Child<span class="token punctuation">)</span> <span class="token function">GetName</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">string</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token string">&quot;Jerry&quot;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 自定义方法，显式调用嵌入结构体的方法</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>c <span class="token operator">*</span>Child<span class="token punctuation">)</span> <span class="token function">Say</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">string</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// 显式指定嵌入结构体，调用其方法（无歧义）</span></span>
<span class="line">    fatherSay <span class="token operator">:=</span> c<span class="token punctuation">.</span>Father<span class="token punctuation">.</span><span class="token function">Say</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">    motherSay <span class="token operator">:=</span> c<span class="token punctuation">.</span>Mother<span class="token punctuation">.</span><span class="token function">Say</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">return</span> fmt<span class="token punctuation">.</span><span class="token function">Sprintf</span><span class="token punctuation">(</span><span class="token string">&quot;I am %s. Father: %s, Mother: %s&quot;</span><span class="token punctuation">,</span> c<span class="token punctuation">.</span><span class="token function">GetName</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> fatherSay<span class="token punctuation">,</span> motherSay<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_3-使用示例" tabindex="-1"><a class="header-anchor" href="#_3-使用示例"><span>3. 使用示例：</span></a></h4><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line">child <span class="token operator">:=</span> <span class="token function">NewChild</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span>child<span class="token punctuation">.</span><span class="token function">Say</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token comment">// 输出：I am Jerry. Father: I am Tony, Mother: I am Aurora</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="核心规则-避免歧义" tabindex="-1"><a class="header-anchor" href="#核心规则-避免歧义"><span>核心规则（避免歧义）</span></a></h4><ul><li><strong>嵌入方式</strong>：支持值嵌入（<code>Father</code>）和指针嵌入（<code>*Mother</code>），指针嵌入需在构造时初始化指针；</li><li><strong>同名方法处理</strong>：若多个嵌入结构体有同名方法，外层结构体必须定义同名方法覆盖（否则调用时会编译报错，提示歧义）；</li><li><strong>显式调用嵌入方法</strong>：通过 <code>c.Father.Say()</code> 显式指定嵌入结构体，避免歧义，这是 Go 处理 “多组合” 冲突的核心方式。</li></ul><h2 id="四、go-与-c-核心区别总结" tabindex="-1"><a class="header-anchor" href="#四、go-与-c-核心区别总结"><span>四、Go 与 C++ 核心区别总结</span></a></h2><table><thead><tr><th>特性</th><th>C++</th><th>Go</th></tr></thead><tbody><tr><td>接口实现</td><td>显式继承（<code>public</code> 接口）</td><td>隐式实现（无需声明，实现方法即满足）</td></tr><tr><td>代码复用</td><td>继承基类</td><td>结构体嵌入（组合）</td></tr><tr><td>多重继承</td><td>支持（易引发菱形继承歧义）</td><td>不支持，通过多嵌入实现多组合（无歧义）</td></tr><tr><td>方法覆盖</td><td>需 <code>override</code> 关键字</td><td>同名方法自动覆盖（外层优先）</td></tr><tr><td>核心设计哲学</td><td>继承优先</td><td>组合优于继承</td></tr></tbody></table><h2 id="五、完整代码仓库" tabindex="-1"><a class="header-anchor" href="#五、完整代码仓库"><span>五、完整代码仓库</span></a></h2><p>本文所有可运行代码已整理至 GitHub，包含接口、组合、多组合的完整示例，可直接克隆运行：<a href="https://github.com/tx7do/go-inheritance-example" target="_blank" rel="noopener noreferrer">https://github.com/tx7do/go-inheritance-example</a></p><h2 id="六、总结" tabindex="-1"><a class="header-anchor" href="#六、总结"><span>六、总结</span></a></h2><p>Go 没有传统 OOP 的 “类” 和 “继承”，但通过 <strong>接口的隐式多态</strong> 和 <strong>结构体的组合（嵌入）</strong>，实现了更灵活、低耦合的代码复用和多态特性：</p><ol><li>接口负责 “约束行为”，隐式实现让代码更简洁，支持多态；</li><li>结构体嵌入负责 “复用代码”，替代传统继承，无耦合问题；</li><li>多嵌入实现类似 “多重继承” 的效果，但通过显式调用避免歧义。</li></ol><p>这种设计既保留了 OOP 的核心优势，又规避了继承带来的复杂问题，是 Go 简洁、高效的关键原因之一。</p>`,56)])])}const i=s(t,[["render",l]]),u=JSON.parse('{"path":"/posts/go_inheritance.html","title":"Go 接口与代码复用：替代继承的设计哲学","lang":"zh-CN","frontmatter":{"date":"2020-01-01T00:00:00.000Z","category":["Go编程"],"tag":["Golang"],"sticky":10},"headers":[{"level":2,"title":"一、前言","slug":"一、前言","link":"#一、前言","children":[]},{"level":2,"title":"二、Go 中的 “单一复用”（类似单一继承）","slug":"二、go-中的-单一复用-类似单一继承","link":"#二、go-中的-单一复用-类似单一继承","children":[{"level":3,"title":"2.1 仅通过接口实现（隐式多态）","slug":"_2-1-仅通过接口实现-隐式多态","link":"#_2-1-仅通过接口实现-隐式多态","children":[]},{"level":3,"title":"2.2 结构体组合（嵌入）实现代码复用（类似基类继承）","slug":"_2-2-结构体组合-嵌入-实现代码复用-类似基类继承","link":"#_2-2-结构体组合-嵌入-实现代码复用-类似基类继承","children":[]}]},{"level":2,"title":"三、Go 中的 “多组合”（类似多重继承）","slug":"三、go-中的-多组合-类似多重继承","link":"#三、go-中的-多组合-类似多重继承","children":[{"level":3,"title":"类比 C++ 伪代码","slug":"类比-c-伪代码-2","link":"#类比-c-伪代码-2","children":[]},{"level":3,"title":"Go 实现代码（多嵌入结构体）","slug":"go-实现代码-多嵌入结构体","link":"#go-实现代码-多嵌入结构体","children":[]}]},{"level":2,"title":"四、Go 与 C++ 核心区别总结","slug":"四、go-与-c-核心区别总结","link":"#四、go-与-c-核心区别总结","children":[]},{"level":2,"title":"五、完整代码仓库","slug":"五、完整代码仓库","link":"#五、完整代码仓库","children":[]},{"level":2,"title":"六、总结","slug":"六、总结","link":"#六、总结","children":[]}],"git":{"updatedTime":1774788457000,"contributors":[{"name":"tx7do","username":"tx7do","email":"yanglinbo@gmail.com","commits":1,"url":"https://github.com/tx7do"},{"name":"Bobo","username":"Bobo","email":"yanglinbo@gmail.com","commits":2,"url":"https://github.com/Bobo"}],"changelog":[{"hash":"a3e88b19cfead00baa606aa5110b2802dac32768","time":1774788457000,"email":"yanglinbo@gmail.com","author":"Bobo","message":"feat: REBUILD."},{"hash":"968a199502c53fc01284dca5fbfc46ce16429a70","time":1764040192000,"email":"yanglinbo@gmail.com","author":"Bobo","message":"feat: edit post."},{"hash":"92ba3da921d6de1c58aaf665d9259d44dac34568","time":1642752988000,"email":"yanglinbo@gmail.com","author":"tx7do","message":"feat: add new post"}]},"filePathRelative":"posts/go_inheritance.md","excerpt":"\\n<h2>一、前言</h2>\\n<p>Go 是 Google 设计的类 C 静态类型语言，兼顾底层性能与开发效率。它并非传统意义上的面向对象（OOP）语言 —— 没有 class 关键字，也不支持传统的 “继承” 语法，但通过 <strong>接口的隐式实现</strong> 和 <strong>结构体组合（嵌入）</strong>，Go 能灵活实现 OOP 的核心特性（多态、代码复用），且设计更简洁、无继承带来的耦合问题。\\n与 C++ 相比，Go 的设计哲学是 “<strong>组合优于继承</strong>”：用接口实现多态，用结构体嵌入实现代码复用，既避免了继承的复杂语法，又解决了多重继承的歧义问题。本文将通过类比 C++ 的接口 / 继承逻辑，详解 Go 如何实现类似效果。</p>"}');export{i as comp,u as data};
